function processRepeaterItem(e){if(!e.classList.contains("rtcl-has-group-title")){e.classList.add("active");const t=e.querySelector('input.ant-radio-input[type="radio"]:checked');t&&"yes"===t.value&&e.classList.add("rtcl-has-group-title")}}jQuery(document).ready(function(e){jQuery(document).on("change",'input.ant-radio-input[type="radio"]',function(){var e=jQuery(this);e.is(":checked")&&"yes"===e.val()?jQuery(this).closest(".rtcl-fb-repeater-item").addClass("rtcl-has-group-title"):jQuery(this).closest(".rtcl-fb-repeater-item").removeClass("rtcl-has-group-title")})}),document.querySelectorAll(".rtcl-fb-repeater-item").forEach(processRepeaterItem);const observer=new MutationObserver(e=>{e.forEach(e=>{e.addedNodes.forEach(e=>{if(1===e.nodeType){(e.matches(".rtcl-fb-repeater-item")?[e]:e.querySelectorAll(".rtcl-fb-repeater-item")).forEach(processRepeaterItem)}})})});observer.observe(document.body,{childList:!0,subtree:!0});
